mapper.select:
 
		 
		select 
			cfgkey, value, comments
		from ( 
				select 
					 ROWNUM rn, cfgkey, value, comments
				from (
						select cfgkey, value, comments
						  from cotdl.tbl_piiconfig 
						 order by cfgkey
					 ) r 
				where 
		
	    
		
						
							and cfgkey like '%'||#{search1}||'%'
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by cfgkey 
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
